sql:
SELECT l.lag_id, l.lag_name, nd.device_name
FROM lags AS l
JOIN network_devices AS nd ON l.device_id = nd.device_id;

SELECT * 
FROM network_devices 
WHERE device_id NOT IN (SELECT DISTINCT device_id FROM lag_members);

external_knowledge:
- 'vessels' metaphorically refers to network devices;
- 'identity' refers to the device name;
- 'habitat' refers to the physical location of the devices;
- 'emblem of unity, "lacp"' is a reference to LAGs starting with "lacp" which symbolizes a form of connection and unity in networking technology.

sql:
SELECT DISTINCT ip_address
FROM network_devices
WHERE vendor IN ('Cisco', 'Juniper');

SELECT AVG(alarm_count) AS average_alarms_per_interface
FROM (
  SELECT interface_id, COUNT(*) AS alarm_count
  FROM alarms
  GROUP BY interface_id
) AS subquery;

SELECT * 
FROM lag_configurations 
WHERE lag_id = 1;

SELECT device_name 
FROM network_devices 
WHERE device_id IN (
  SELECT device_id 
  FROM lags
);

SELECT lc.config_id, l.lag_name, lc.config_name
FROM lag_configurations lc
INNER JOIN lags l ON lc.lag_id = l.lag_id;

external_knowledge:
- Network devices are like lighthouses guiding boats (network traffic) through their waters (network).;
- The number of interfaces a device has is akin to the number of beacons a lighthouse possesses.;
- The highest recorded bandwidth usage represents the most powerful signal emitted by the lighthouse.;
- The username associated with each device represents the watchful eye (user) overseeing the lighthouse's operations.

sql:
SELECT alarm_severity, COUNT(alarm_id) as alarm_count
FROM alarms
GROUP BY alarm_severity;

SELECT DISTINCT nd.device_name
FROM network_devices nd
INNER JOIN lags l ON nd.device_id = l.device_id;

SELECT u.user_id, u.username, u.email, u.last_login_date
FROM users u
WHERE u.last_login_date < (
    SELECT MAX(log_date) 
    FROM audit_logs
);
